            }
            is OnionException.InvalidEnvelope -> {
                buf.putInt(2)
                Unit
            }
            is OnionException.UnsupportedVersion -> {
                buf.putInt(3)
                Unit
            }
            is OnionException.Encrypt -> {
                buf.putInt(4)
                Unit
            }
            is OnionException.Decrypt -> {
                buf.putInt(5)
                Unit
            }
            is OnionException.InvalidPayload -> {
                buf.putInt(6)
                Unit
            }
            is OnionException.InvalidKey -> {
                buf.putInt(7)
                Unit
            }
        }.let { /* this makes the `when` an expression, which ensures it is exhaustive */ }
    }

}




